    private static QuizQuestion MedienUndVerfahren(Random r)
    {
        var f = MedienUndVerfahrenListe[r.Next(MedienUndVerfahrenListe.Length)];
        return new QuizQuestion
        {
            Id = NewId(), Subject = Subject.Kunst, GradeLevel = GradeLevel.Klasse6,
            Topic = "Medien und Verfahren", Type = QuestionType.MultipleChoice,
            Prompt = f.Frage, Options = f.Optionen, CorrectAnswers = new[] { f.Antwort }, Explanation = f.Erklaerung,
            HelpHint = "Medien wie Bilder, Filme oder Bücher können als Inspiration dienen; Skizzenbuch, Schraffur und Modellbau gehören zu den grundlegenden Verfahren."
        };
    }

