            Prompt = f.Frage, Options = f.Optionen, CorrectAnswers = new[] { f.Antwort }, Explanation = f.Erklaerung,
            HelpHint = "Kunst kann eigene Gefühle, Werte, Freundschaften oder den Übergang zur Jugend sichtbar machen - überlege, wie ein Bild etwas über dich erzählen könnte."
